async function fetchLeaderboard() {
	try {
		const res = await fetch("http://localhost:8001/api/leaderboard");
		if (!res.ok) return [];
		return (await res.json()).map((e) => ({
			name: e.name,
			time: e.time
		}));
	} catch {
		return [];
	}
}
